890→        matchedEventIds: [existing.eventId],
891→        matchedPointIds: [existing.pointId],
892→        confidence: Math.max(60, 95 - distance * 7),
893→        action: 'flag',
894→        reason: `Near-duplicate photo detected (hamming distance: ${distance}/64)`,
895→      };
896→    }
897→  }
898→
899→  // ── Step 3: EXIF fingerprint match ──
900→  // Same device, same time, same GPS -- different submission
901→  if (params.photoMetadata.capturedAt && params.photoMetadata.gps) {
