929→### 3.2 Entity Deduplication
930→
931→```typescript
932→// lib/server/entityDedup.ts
933→
934→interface EntityDedupResult {
935→  isDuplicate: boolean;
936→  matchType: 'exact_location' | 'proximity_name' | 'cross_agent' | 'temporal' | 'none';
937→  matchedPointId: string | null;
938→  confidence: number;
939→  action: 'allow' | 'suggest_enrich' | 'flag' | 'reject';
940→  reason: string | null;
941→}
942→
943→// Category-specific proximity thresholds (in km)
944→// Calibrated for Bonamoussadi's commercial density
945→const PROXIMITY_THRESHOLDS: Record<string, {
946→  rejectKm: number;      // Auto-reject: almost certainly same entity
947→  flagKm: number;        // Flag for review: probably same entity
948→  enrichSuggestKm: number; // Suggest enrichment instead of creation
949→}> = {
950→  mobile_money:   { rejectKm: 0.010, flagKm: 0.020, enrichSuggestKm: 0.050 },
951→  pharmacy:       { rejectKm: 0.030, flagKm: 0.050, enrichSuggestKm: 0.100 },
952→  fuel_station:   { rejectKm: 0.050, flagKm: 0.100, enrichSuggestKm: 0.200 },
953→  alcohol_outlet: { rejectKm: 0.015, flagKm: 0.030, enrichSuggestKm: 0.060 },
954→  billboard:      { rejectKm: 0.010, flagKm: 0.020, enrichSuggestKm: 0.050 },
955→  transport_road: { rejectKm: 0.020, flagKm: 0.050, enrichSuggestKm: 0.100 },
956→  census_proxy:   { rejectKm: 0.015, flagKm: 0.030, enrichSuggestKm: 0.060 },
957→};
958→
959→async function checkEntityDuplicate(params: {
960→  category: string;
961→  location: SubmissionLocation;
962→  name: string;
963→  userId: string;
964→  eventType: 'CREATE_EVENT' | 'ENRICH_EVENT';
965→}): Promise<EntityDedupResult> {
966→
967→  // Only check duplicates for CREATE_EVENTs
968→  if (params.eventType === 'ENRICH_EVENT') {
969→    return { isDuplicate: false, matchType: 'none', matchedPointId: null,
970→             confidence: 0, action: 'allow', reason: null };
971→  }
972→
973→  const thresholds = PROXIMITY_THRESHOLDS[params.category] ??
974→    { rejectKm: 0.020, flagKm: 0.050, enrichSuggestKm: 0.100 };
975→
976→  // Fetch all existing points of the same category within the
977→  // enrichSuggest radius (widest check radius)
978→  const nearbyPoints = await findPointsByProximity(
979→    params.category,
980→    params.location,
981→    thresholds.enrichSuggestKm
982→  );
983→
984→  if (nearbyPoints.length === 0) {
985→    return { isDuplicate: false, matchType: 'none', matchedPointId: null,
986→             confidence: 0, action: 'allow', reason: null };
987→  }
988→
989→  // Check each nearby point
990→  for (const point of nearbyPoints) {
991→    const distKm = haversineKm(params.location, point.location);
992→    const nameSimilarity = computeNameSimilarity(params.name, point.name ?? '');
993→
994→    // ── EXACT LOCATION MATCH ──
995→    if (distKm < thresholds.rejectKm) {
996→      return {
997→        isDuplicate: true,
998→        matchType: 'exact_location',
999→        matchedPointId: point.pointId,

 999→        matchedPointId: point.pointId,
1000→        confidence: 95,
1001→        action: 'suggest_enrich',
1002→        reason: `A ${params.category} already exists ${Math.round(distKm * 1000)}m away (${point.name}). Did you mean to enrich it?`,
1003→      };
1004→    }
1005→
1006→    // ── PROXIMITY + NAME MATCH ──
1007→    if (distKm < thresholds.flagKm && nameSimilarity > 0.7) {
1008→      return {
1009→        isDuplicate: true,
1010→        matchType: 'proximity_name',
1011→        matchedPointId: point.pointId,
1012→        confidence: 85,
1013→        action: 'suggest_enrich',
1014→        reason: `"${point.name}" already exists ${Math.round(distKm * 1000)}m away with ${Math.round(nameSimilarity * 100)}% name similarity`,
1015→      };
1016→    }
1017→
1018→    // ── PROXIMITY FLAG ──
1019→    if (distKm < thresholds.flagKm) {
1020→      return {
1021→        isDuplicate: true,
1022→        matchType: 'proximity_name',
1023→        matchedPointId: point.pointId,
1024→        confidence: 60,
1025→        action: 'flag',
1026→        reason: `Another ${params.category} exists ${Math.round(distKm * 1000)}m away (${point.name}). Possibly a duplicate.`,
1027→      };
1028→    }
1029→
1030→    // ── ENRICH SUGGESTION ZONE ──
1031→    if (distKm < thresholds.enrichSuggestKm && nameSimilarity > 0.8) {
1032→      return {
1033→        isDuplicate: true,
1034→        matchType: 'proximity_name',
1035→        matchedPointId: point.pointId,
1036→        confidence: 50,
1037→        action: 'flag',
1038→        reason: `Similar ${params.category} "${point.name}" exists ${Math.round(distKm * 1000)}m away`,
1039→      };
1040→    }
1041→  }
1042→
1043→  return { isDuplicate: false, matchType: 'none', matchedPointId: null,
1044→           confidence: 0, action: 'allow', reason: null };
1045→}
1046→
1047→// ── NAME SIMILARITY ──
1048→// Normalized Levenshtein distance with preprocessing for
1049→// Cameroonian French business names
1050→
1051→function computeNameSimilarity(name1: string, name2: string): number {
1052→  const normalize = (s: string) => s
1053→    .toLowerCase()
1054→    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')  // Remove accents
1055→    .replace(/[^a-z0-9\s]/g, '')                        // Remove punctuation
1056→    .replace(/\b(pharmacie|pharmacy|station|kiosque|agence|bar|buvette|depot)\b/g, '') // Remove common prefixes
1057→    .replace(/\b(de|du|des|la|le|les|l)\b/g, '')       // Remove articles
1058→    .replace(/\s+/g, ' ')
1059→    .trim();
1060→
1061→  const n1 = normalize(name1);
1062→  const n2 = normalize(name2);
1063→
1064→  if (n1 === n2) return 1.0;
1065→  if (!n1 || !n2) return 0.0;
1066→
1067→  // Levenshtein distance
1068→  const len1 = n1.length;
1069→  const len2 = n2.length;
1070→  const matrix: number[][] = Array.from({ length: len1 + 1 }, () =>
1071→    Array(len2 + 1).fill(0)
1072→  );
1073→
1074→  for (let i = 0; i <= len1; i++) matrix[i][0] = i;
1075→  for (let j = 0; j <= len2; j++) matrix[0][j] = j;
1076→
1077→  for (let i = 1; i <= len1; i++) {
1078→    for (let j = 1; j <= len2; j++) {
1079→      const cost = n1[i - 1] === n2[j - 1] ? 0 : 1;
1080→      matrix[i][j] = Math.min(
1081→        matrix[i - 1][j] + 1,
1082→        matrix[i][j - 1] + 1,
1083→        matrix[i - 1][j - 1] + cost
1084→      );
1085→    }
1086→  }
1087→
1088→  const maxLen = Math.max(len1, len2);
1089→  return maxLen === 0 ? 1.0 : 1.0 - matrix[len1][len2] / maxLen;
1090→}
