1162→// ── TEMPORAL DUPLICATE DETECTION ──
1163→// Same entity submitted too frequently by the same or different agents
1164→
1165→async function detectTemporalDuplicates(
1166→  pointId: string,
1167→  windowHours: number = 24
1168→): Promise<{
1169→  isDuplicate: boolean;
1170→  recentEventCount: number;
1171→  uniqueAgents: number;
1172→  action: 'allow' | 'throttle' | 'reject';
1173→}> {
1174→  const recentEvents = await getRecentEventsForPoint(pointId, windowHours);
1175→
1176→  if (recentEvents.length === 0) {
1177→    return { isDuplicate: false, recentEventCount: 0, uniqueAgents: 0, action: 'allow' };
1178→  }
1179→
1180→  const uniqueAgents = new Set(recentEvents.map(e => e.userId)).size;
1181→
1182→  // Thresholds:
1183→  // - Same agent enriching same point 3+ times in 24h: throttle
1184→  // - Any agent enriching a point that was enriched <1h ago: flag
1185→  // - 5+ enrichments on same point in 24h from any agents: suspicious
1186→  if (recentEvents.length >= 5) {
1187→    return {
1188→      isDuplicate: true,
1189→      recentEventCount: recentEvents.length,
1190→      uniqueAgents,
1191→      action: 'reject',
1192→    };
1193→  }
1194→
1195→  const mostRecent = recentEvents[0];
1196→  const timeSinceLastMs = Date.now() - new Date(mostRecent.createdAt).getTime();
1197→  if (timeSinceLastMs < 3600000) { // Less than 1 hour
1198→    return {
1199→      isDuplicate: true,
1200→      recentEventCount: recentEvents.length,
1201→      uniqueAgents,
1202→      action: 'throttle',
1203→    };
1204→  }
1205→
1206→  return {
1207→    isDuplicate: false,
1208→    recentEventCount: recentEvents.length,
1209→    uniqueAgents,
1210→    action: 'allow',
1211→  };
1212→}
